```jsx
// Parent
const handleClick = useCallback(() => doThing(id), [id]);
const config = useMemo(() => ({ theme: 'dark' }), []);

return <Child onClick={handleClick} config={config} />;
```

```jsx
// Child
const Child = React.memo(({ onClick, config }) => {
  return <div onClick={onClick}>{config.theme}</div>;
});
```

Debug with React DevTools Profiler — "Why did this render?" shows which props changed.
